package main
import "fmt"
func main() {
    var num, animal, conta int
    var Animais []int

    fmt.Scan(&num)
    for i:=0; i<num; i++{
        fmt.Scan(&animal)
        Animais = append(Animais, animal)
    }

    for i := 0; i < len(Animais); i++{
        for j := i+1; j < len(Animais); j++{
            if Animais[j] == Animais[i]*(-1){
                Animais = append(Animais[:j], Animais[j+1:]...)
                Animais = append(Animais[:i], Animais[i+1:]...)
                conta++
                i--
                break
            }
        }
    }
    fmt.Println(conta)

}
